25	// CSIConfig 存储CSI相关信息
26	type CSIConfig struct {
27		Driver            string                               `json:"driver"`
28		SecretName        string                               `json:"secretName"`
29		SecretNamespace   string                               `json:"secretNamespace"`
30		JuiceFSImage      string                               `json:"juicefsImage"`
31		MountOptions      []string                             `json:"mountOptions"`
32		Parameters        map[string]string                    `json:"parameters"`
33		ReclaimPolicy     corev1.PersistentVolumeReclaimPolicy `json:"reclaimPolicy"`
34		VolumeBindingMode storagev1.VolumeBindingMode          `json:"volumeBindingMode"`
35	}
36	
37	var (
38		csiConfig   *CSIConfig
39		configMutex sync.RWMutex
40	)
