18	// Service 开发机服务接口
19	type Service interface {
20		CreatePod(ctx context.Context, pod *k8s.PodSpec) error
21		DeletePod(ctx context.Context, name string) error
22		GetPod(ctx context.Context, name string) (*k8s.PodInfo, error)
23		ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error)
24		GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error)
25	
26		CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error)
27		UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error)
28		DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error)
29		GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error)
30		ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error)
31		StartDevmachine(ctx context.Context, namespace, name string) error
32		StopDevmachine(ctx context.Context, namespace, name string) error
33		GetDevmachineStatus(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineStatusResponse, error)
34		CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error)
35	}
36	
37	type service struct {
38		k8sClient k8s.Client
39		config    *config.Config
40	}
41	
42	// NewService 创建开发机服务
43	func NewService(k8sClient k8s.Client, cfg *config.Config) Service {
44		// 初始化CSI配置
45		if err := SyncCSIConfigFromStorageClass(k8sClient); err != nil {
46			log.Printf("warning: failed to sync CSI config from storage class: %v", err)
47		}
48	
49		// 检查并创建集群共享 PV（如不存在则自动创建）
50		svc := &service{k8sClient: k8sClient, config: cfg}
51		if err := svc.ensureSharedPVs(context.Background()); err != nil {
52			log.Printf("warning: failed to ensure shared PVs: %v", err)
53		}
54	
55		// 启动CSI配置同步循环
56		StartCSISyncLoop(k8sClient)
57	
58		// 启动Ingress URL同步循环
59		StartIngressURLSyncLoop(k8sClient)
60	
61		return svc
62	}
63	
64	func (s *service) CreatePod(ctx context.Context, pod *k8s.PodSpec) error {
65		if err := ValidatePodRequest(pod.Name, pod.Image); err != nil {
66			return NewValidationError("pod.Name", pod.Name, err)
67		}
68		return s.k8sClient.CreatePod(ctx, pod)
69	}
70	
71	func (s *service) DeletePod(ctx context.Context, name string) error {
72		if err := ValidatePodName(name); err != nil {
73			return NewValidationError("pod.Name", name, err)
74		}
75		return s.k8sClient.DeletePod(ctx, name)
76	}
77	
78	func (s *service) GetPod(ctx context.Context, name string) (*k8s.PodInfo, error) {
79		if err := ValidatePodName(name); err != nil {
80			return nil, NewValidationError("pod.Name", name, err)
81		}
82		return s.k8sClient.GetPod(ctx, name)
83	}
84	
85	func (s *service) ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error) {
86		return s.k8sClient.ListPods(ctx, labels)
87	}
88	
89	func (s *service) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
90		if err := ValidatePodName(name); err != nil {
91			return "", NewValidationError("pod.Name", name, err)
92		}
93		if tailLines <= 0 {
94			tailLines = 100
95		}
96		return s.k8sClient.GetPodLogs(ctx, name, tailLines)
97	}
98	
99	func (s *service) CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error) {
100		// 验证请求参数
101		if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
102			return nil, NewValidationError("devmachine", request.Name, err)
103		}
104	
105		var err error
106	
107		defer func() {
108			if err != nil {
109				log.Printf("error: failed to create devmachine, try to cleanup: %v", err)
110				_, _ = s.DeleteDevmachine(ctx, request.Namespace, request.Name)
111			}
112		}()
113	
114		// 1. 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 补建）
115		// TODO: 新环境稳定后可移除此兼容逻辑
116		if len(request.Storage) > 0 {
117			if err = s.ensureSharedPVCs(ctx, request.Namespace, request.Storage); err != nil {
118				return nil, err
119			}
120		}
121	
122		// 3. 创建 Deployment
123		deployment := generateDevMachineDeployment(request, s.config.InitContainer.Image)
124		if err := s.k8sClient.CreateDeployment(ctx, deployment); err != nil {
125			return nil, NewResourceError("Deployment", request.Name, "create", err)
126		}
127	
128		// 3. 创建 Service
129		service := generateDevMachineService(request)
130		if err := s.k8sClient.CreateService(ctx, service); err != nil {
131			return nil, NewResourceError("Service", request.Name+serviceSuffix, "create", err)
132		}
133	
134		// 4. 创建 Ingress
135		ingress := generateDevMachineIngress(request)
136		if err := s.k8sClient.CreateIngress(ctx, ingress); err != nil {
137			return nil, NewResourceError("Ingress", request.Name+ingressSuffix, "create", err)
138		}
139	
140		return &devmachinemodel.CreateDevmachineResponse{
141			Name:   request.Name,
142			Status: "pending",
143			WebUrl: fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(request.Namespace, request.Name)),
144		}, nil
145	}
