206	func (s *service) DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error) {
207		// 1. 删除 Ingress
208		if err := s.k8sClient.DeleteIngress(ctx, namespace, name+ingressSuffix); err != nil {
209			// 记录错误但继续删除其他资源
210			log.Printf("warning: failed to delete ingress: %v\n", err)
211		}
212	
213		// 2. 删除 Service
214		if err := s.k8sClient.DeleteService(ctx, namespace, name+serviceSuffix); err != nil {
215			log.Printf("warning: failed to delete service: %v\n", err)
216		}
217	
218		// 3. 删除 Deployment
219		if err := s.k8sClient.DeleteDeployment(ctx, namespace, name); err != nil {
220			log.Printf("warning: failed to delete deployment: %v\n", err)
221		}
222	
223		// PVC 和 PV 为共享资源，随 namespace 生命周期管理，不随开发机删除
224	
225		// 返回删除时间
226		return &devmachinemodel.DeleteDevmachineResponse{
227			DeleteAt: time.Now().Format(time.RFC3339),
228		}, nil
229	}
