435	// ensureSharedPVs 服务启动时检查并创建集群共享 PV（如不存在则自动创建）
436	func (s *service) ensureSharedPVs(ctx context.Context) error {
437		pvConfigs := []struct {
438			cfg      config.SharedPVConfig
439			readOnly bool
440		}{
441			{s.config.SharedStorage.RWPV, false},
442			{s.config.SharedStorage.ROPV, true},
443		}
444	
445		for _, item := range pvConfigs {
446			if item.cfg.Name == "" {
447				continue
448			}
449			exists, err := s.k8sClient.PVExists(ctx, item.cfg.Name)
450			if err != nil {
451				return fmt.Errorf("check shared PV %s: %w", item.cfg.Name, err)
452			}
453			if !exists {
454				log.Printf("[startup] shared PV %s not found, creating...", item.cfg.Name)
455				pv, err := buildSharedPV(item.cfg.Name, item.cfg.SubPath, item.readOnly)
456				if err != nil {
457					return fmt.Errorf("build shared PV %s: %w", item.cfg.Name, err)
458				}
459				if err := s.k8sClient.CreatePV(ctx, pv); err != nil {
460					return fmt.Errorf("create shared PV %s: %w", item.cfg.Name, err)
461				}
462			}
463		}
464		return nil
465	}
466	
467	// ensureSharedPVCs 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 无 PVC 时补建）
468	// TODO: 新环境稳定后可移除
469	func (s *service) ensureSharedPVCs(ctx context.Context, namespace string, storages []devmachinemodel.Storage) error {
470		needsRW, needsRO := false, false
471		for _, st := range storages {
472			if st.ReadOnly {
473				needsRO = true
474			} else {
475				needsRW = true
476			}
477		}
478	
479		if needsRW {
480			if err := s.ensurePVCExists(ctx, namespace, SharedRWPVCName, s.config.SharedStorage.RWPV.Name, false); err != nil {
481				return err
482			}
483		}
484		if needsRO {
485			if err := s.ensurePVCExists(ctx, namespace, SharedROPVCName, s.config.SharedStorage.ROPV.Name, true); err != nil {
486				return err
487			}
488		}
489		return nil
490	}
491	
492	// ensurePVCExists 检查 PVC 是否存在，不存在则创建
493	func (s *service) ensurePVCExists(ctx context.Context, namespace, pvcName, pvName string, readOnly bool) error {
494		exists, err := s.k8sClient.PVCExists(ctx, namespace, pvcName)
495		if err != nil {
496			return fmt.Errorf("check PVC %s/%s: %w", namespace, pvcName, err)
497		}
498		if !exists {
499			log.Printf("[compat] shared PVC %s not found in namespace %s, creating...", pvcName, namespace)
500			return s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, pvcName, pvName, readOnly))
501		}
502		return nil
503	}
504	
505	// createSharedPVCs 为 namespace 创建读写和只读共享 PVC
506	func (s *service) createSharedPVCs(ctx context.Context, namespace string) error {
507		rwPVC := buildSharedPVC(namespace, SharedRWPVCName, s.config.SharedStorage.RWPV.Name, false)
508		if err := s.k8sClient.CreatePVC(ctx, rwPVC); err != nil {
509			return fmt.Errorf("create shared-rw-pvc in %s: %w", namespace, err)
510		}
511		roPVC := buildSharedPVC(namespace, SharedROPVCName, s.config.SharedStorage.ROPV.Name, true)
512		if err := s.k8sClient.CreatePVC(ctx, roPVC); err != nil {
513			return fmt.Errorf("create shared-ro-pvc in %s: %w", namespace, err)
514		}
515		return nil
516	}
517	
518	func (s *service) CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error) {
519		// 验证请求参数
520		if request.Namespace == "" {
521			return nil, NewValidationError("namespace", request.Namespace, fmt.Errorf("namespace cannot be empty"))
522		}
523	
524		// 创建命名空间
525		if err := s.k8sClient.CreateNamespace(ctx, request.Namespace); err != nil {
526			return nil, NewResourceError("Namespace", request.Namespace, "create", err)
527		}
528	
529		// 为新 namespace 创建共享 PVC
530		if err := s.createSharedPVCs(ctx, request.Namespace); err != nil {
531			log.Printf("warning: failed to create shared PVCs in namespace %s: %v", request.Namespace, err)
532			// 注意：PVC 创建失败不影响 namespace 创建的成功响应，兼容兜底会在首次创建开发机时补建
533		}
534	
535		return &devmachinemodel.CreateNamespaceResponse{
536			Message: fmt.Sprintf("namespace %s created successfully", request.Namespace),
537		}, nil
538	}
