package config

import (
	"fmt"
	"os"

	"github.com/spf13/viper"

	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/service/resource"
)

type Config struct {
	Server        ServerConfig        `mapstructure:"server"`
	Log           LogConfig           `mapstructure:"log"`
	Auth          AuthConfig          `mapstructure:"auth"`
	S3            S3Config            `mapstructure:"s3"`
	Harbor        HarborConfig        `mapstructure:"harbor"`
	K8s           K8sConfig           `mapstructure:"k8s"`
	TDSC          TDSCConfig          `mapstructure:"tdsc"`
	Resources     ResourcesConfig     `mapstructure:"resources"`
	InitContainer InitContainerConfig `mapstructure:"initContainer"`
	SharedStorage SharedStorageConfig `mapstructure:"sharedStorage"`
	Registration  RegistrationConfig  `mapstructure:"registration"`
}

type ServerConfig struct {
	Mode string `mapstructure:"mode"`
}

type LogConfig struct {
	Level              string `mapstructure:"level"`
	OutputPath         string `mapstructure:"outputPath"`
	PrintRequestParams bool   `mapstructure:"printRequestParams"` // 是否打印请求参数
	SkipFileOperations bool   `mapstructure:"skipFileOperations"` // 是否跳过文件上传/下载请求
}

type AuthConfig struct {
	Enabled   bool       `mapstructure:"enabled"`  // 是否启用认证
	AuthType  string     `mapstructure:"authType"` // 认证类型: "jwt" 或 "basic_auth"
	JWTSecret string     `mapstructure:"jwtSecret"`
	TokenTTL  int        `mapstructure:"tokenTtl"` // 秒
	Users     []UserInfo `mapstructure:"users"`    // 预设用户列表
}

type UserInfo struct {
	Username string `mapstructure:"username"`
	Password string `mapstructure:"password"`
	UserID   string `mapstructure:"userId"` // 可选，默认使用 username
}

type S3Config struct {
	Endpoint  string `mapstructure:"endpoint"`
	AccessKey string `mapstructure:"accessKey"`
	SecretKey string `mapstructure:"secretKey"`
	Bucket    string `mapstructure:"bucket"`
	Region    string `mapstructure:"region"`
}

type HarborConfig struct {
	URL      string `mapstructure:"url"`
	Domain   string `mapstructure:"domain"`
	Username string `mapstructure:"username"`
	Password string `mapstructure:"password"`
}

type K8sConfig struct {
	Kubeconfig string `mapstructure:"kubeconfig"`
	Namespace  string `mapstructure:"namespace"`
}

type TDSCConfig struct {
	Vol string `mapstructure:"vol"`
	URL string `mapstructure:"url"`
}

type ResourcesConfig struct {
	GPUTypes []resource.GPUType `mapstructure:"gpuTypes"`
}

type InitContainerConfig struct {
	Image string `mapstructure:"image"`
}

type SharedStorageConfig struct {
	RWPV SharedPVConfig `mapstructure:"rwPV"`
	ROPV SharedPVConfig `mapstructure:"roPV"`
}

type SharedPVConfig struct {
	Name    string `mapstructure:"name"`
	SubPath string `mapstructure:"subPath"`
}
type RegistrationConfig struct {
	Enabled      bool   `mapstructure:"enabled"`      // 是否启用注册上报
	BaseURL      string `mapstructure:"baseUrl"`      // 上层TDP EDU服务地址
	AccessKey    string `mapstructure:"accessKey"`    // 访问密钥
	SecretKey    string `mapstructure:"secretKey"`    // 密钥
	CloudCode    string `mapstructure:"cloudCode"`    // 云编码 (如：ctyun)
	CloudName    string `mapstructure:"cloudName"`    // 云名称 (如：天翼云)
	CloudAddress string `mapstructure:"cloudAddress"` // 云服务地址（必填），如：192.168.xx.xx:8080
}

func Load(path string) (*Config, error) {
	viper.SetConfigFile(path)
	viper.SetConfigType("yaml")

	// 设置默认值
	viper.SetDefault("server.mode", "debug")
	viper.SetDefault("log.level", "info")
	viper.SetDefault("log.outputPath", "stdout")
	viper.SetDefault("log.printRequestParams", false)
	viper.SetDefault("log.skipFileOperations", true)
	viper.SetDefault("auth.tokenTtl", 3600)
	viper.SetDefault("auth.authType", "jwt")
	viper.SetDefault("auth.authType", "jwt")
	viper.SetDefault("k8s.namespace", "default")
	viper.SetDefault("initContainer.image", "gz01-srdart.srdcloud.cn/tdp-paas/tdp_paas-tap-snapshot-docker-local/dev-bootstrap:v1.0.1-rc2")
	viper.SetDefault("sharedStorage.rwPV.name", "shared-rw-pv")
	viper.SetDefault("sharedStorage.rwPV.subPath", "")
	viper.SetDefault("sharedStorage.roPV.name", "shared-ro-pv")
	viper.SetDefault("sharedStorage.roPV.subPath", "")
	viper.SetDefault("registration.enabled", false)

	// 允许从环境变量读取
	viper.AutomaticEnv()

	if err := viper.ReadInConfig(); err != nil {
		if _, ok := err.(viper.ConfigFileNotFoundError); !ok {
			return nil, fmt.Errorf("error reading config file: %w", err)
		}
		// 配置文件不存在时使用默认值
	}

	var cfg Config
	if err := viper.Unmarshal(&cfg); err != nil {
		return nil, fmt.Errorf("error unmarshaling config: %w", err)
	}

	// 设置认证开关的默认值（如果配置文件中没有设置）
	if !viper.IsSet("auth.enabled") {
		if cfg.Server.Mode == "debug" {
			cfg.Auth.Enabled = false
		} else {
			cfg.Auth.Enabled = true
		}
	}

	// 从环境变量覆盖敏感信息
	if jwtSecret := os.Getenv("JWT_SECRET"); jwtSecret != "" {
		cfg.Auth.JWTSecret = jwtSecret
	}
	if s3Key := os.Getenv("S3_ACCESS_KEY"); s3Key != "" {
		cfg.S3.AccessKey = s3Key
	}
	if s3Secret := os.Getenv("S3_SECRET_KEY"); s3Secret != "" {
		cfg.S3.SecretKey = s3Secret
	}
	if harborPass := os.Getenv("HARBOR_PASSWORD"); harborPass != "" {
		cfg.Harbor.Password = harborPass
	}
	if authEnabled := os.Getenv("AUTH_ENABLED"); authEnabled != "" {
		if authEnabled == "true" {
			cfg.Auth.Enabled = true
		} else if authEnabled == "false" {
			cfg.Auth.Enabled = false
		}
	}

	// 从环境变量覆盖注册上报配置
	if regEnabled := os.Getenv("REGISTRATION_ENABLED"); regEnabled != "" {
		if regEnabled == "true" {
			cfg.Registration.Enabled = true
		} else if regEnabled == "false" {
			cfg.Registration.Enabled = false
		}
	}
	if regAccessKey := os.Getenv("REGISTRATION_ACCESS_KEY"); regAccessKey != "" {
		cfg.Registration.AccessKey = regAccessKey
	}
	if regSecretKey := os.Getenv("REGISTRATION_SECRET_KEY"); regSecretKey != "" {
		cfg.Registration.SecretKey = regSecretKey
	}
	if regCloudAddress := os.Getenv("REGISTRATION_CLOUD_ADDRESS"); regCloudAddress != "" {
		cfg.Registration.CloudAddress = regCloudAddress
	}

	// 验证认证类型
	if cfg.Auth.Enabled && cfg.Auth.AuthType != "jwt" && cfg.Auth.AuthType != "basic_auth" {
		return nil, fmt.Errorf("invalid auth_type: %s, must be 'jwt' or 'basic_auth'", cfg.Auth.AuthType)
	}

	return &cfg, nil
}

package devmachine

import (
	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
	corev1 "k8s.io/api/core/v1"

	devmachinemodel "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/devmachine"
)

var _ = Describe("Storage Builder", func() {
	Describe("buildSharedPVC", func() {
		Context("when readOnly is false", func() {
			It("should create ReadWriteMany PVC explicitly bound to the given PV", func() {
				pvc := buildSharedPVC("test-ns", "shared-rw-pvc", "shared-rw-pv", false)

				Expect(pvc.Name).To(Equal("shared-rw-pvc"))
				Expect(pvc.Namespace).To(Equal("test-ns"))
				Expect(pvc.Spec.VolumeName).To(Equal("shared-rw-pv"))
				Expect(pvc.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadWriteMany}))
				Expect(pvc.Spec.StorageClassName).NotTo(BeNil())
				Expect(*pvc.Spec.StorageClassName).To(Equal(""))
			})
		})

		Context("when readOnly is true", func() {
			It("should create ReadOnlyMany PVC", func() {
				pvc := buildSharedPVC("test-ns", "shared-ro-pvc", "shared-ro-pv", true)

				Expect(pvc.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadOnlyMany}))
				Expect(pvc.Spec.VolumeName).To(Equal("shared-ro-pv"))
			})
		})
	})

	Describe("buildSharedVolumes", func() {
		Context("when storage list is empty", func() {
			It("should return nil", func() {
				volumes := buildSharedVolumes(nil)
				Expect(volumes).To(BeNil())
			})
		})

		Context("when all storages are read-write", func() {
			It("should return 1 volume named shared-rw-volume referencing shared-rw-pvc", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
					{StoragePath: "user/code", MountPath: "/code", ReadOnly: false},
				}
				volumes := buildSharedVolumes(storages)

				Expect(volumes).To(HaveLen(1))
				Expect(volumes[0].Name).To(Equal(SharedRWVolumeName))
				Expect(volumes[0].PersistentVolumeClaim).NotTo(BeNil())
				Expect(volumes[0].PersistentVolumeClaim.ClaimName).To(Equal(SharedRWPVCName))
			})
		})

		Context("when all storages are read-only", func() {
			It("should return 1 volume named shared-ro-volume referencing shared-ro-pvc with ReadOnly=true", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "shared/models", MountPath: "/models", ReadOnly: true},
				}
				volumes := buildSharedVolumes(storages)

				Expect(volumes).To(HaveLen(1))
				Expect(volumes[0].Name).To(Equal(SharedROVolumeName))
				Expect(volumes[0].PersistentVolumeClaim).NotTo(BeNil())
				Expect(volumes[0].PersistentVolumeClaim.ClaimName).To(Equal(SharedROPVCName))
				Expect(volumes[0].PersistentVolumeClaim.ReadOnly).To(BeTrue())
			})
		})

		Context("when storages include both RW and RO", func() {
			It("should return exactly 2 volumes without duplicates", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "path/a", MountPath: "/a", ReadOnly: false},
					{StoragePath: "path/b", MountPath: "/b", ReadOnly: false},
					{StoragePath: "path/c", MountPath: "/c", ReadOnly: true},
				}
				volumes := buildSharedVolumes(storages)

				Expect(volumes).To(HaveLen(2))
				volumeNames := make([]string, len(volumes))
				for i, v := range volumes {
					volumeNames[i] = v.Name
				}
				Expect(volumeNames).To(ContainElement(SharedRWVolumeName))
				Expect(volumeNames).To(ContainElement(SharedROVolumeName))
			})
		})
	})

	Describe("buildSharedVolumeMounts", func() {
		Context("when storage list is empty", func() {
			It("should return nil", func() {
				mounts := buildSharedVolumeMounts(nil)
				Expect(mounts).To(BeNil())
			})
		})

		Context("when storages have RW and RO entries", func() {
			It("should map StoragePath to SubPath and MountPath correctly", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/workspace/data", ReadOnly: false},
					{StoragePath: "shared/models", MountPath: "/models", ReadOnly: true},
				}
				mounts := buildSharedVolumeMounts(storages)

				Expect(mounts).To(HaveLen(2))
				Expect(mounts[0].Name).To(Equal(SharedRWVolumeName))
				Expect(mounts[0].SubPath).To(Equal("user/data"))
				Expect(mounts[0].MountPath).To(Equal("/workspace/data"))
				Expect(mounts[0].ReadOnly).To(BeFalse())

				Expect(mounts[1].Name).To(Equal(SharedROVolumeName))
				Expect(mounts[1].SubPath).To(Equal("shared/models"))
				Expect(mounts[1].MountPath).To(Equal("/models"))
				Expect(mounts[1].ReadOnly).To(BeTrue())
			})
		})

		Context("when multiple storages share the same RW volume", func() {
			It("should create separate mounts each with their own subPath", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "project/a", MountPath: "/data/a", ReadOnly: false},
					{StoragePath: "project/b", MountPath: "/data/b", ReadOnly: false},
				}
				mounts := buildSharedVolumeMounts(storages)

				Expect(mounts).To(HaveLen(2))
				Expect(mounts[0].Name).To(Equal(SharedRWVolumeName))
				Expect(mounts[0].SubPath).To(Equal("project/a"))
				Expect(mounts[1].Name).To(Equal(SharedRWVolumeName))
				Expect(mounts[1].SubPath).To(Equal("project/b"))
			})
		})
	})

	Describe("buildSharedPV", func() {
		Context("when csiConfig is nil", func() {
			BeforeEach(func() {
				SetCSIConfig(nil)
			})

			It("should return an error without panicking", func() {
				pv, err := buildSharedPV("shared-rw-pv", "", false)

				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("CSI config not initialized"))
				Expect(pv).To(BeNil())
			})
		})

		Context("when csiConfig is initialized", func() {
			BeforeEach(func() {
				SetCSIConfig(&CSIConfig{
					Driver:          "csi.juicefs.com",
					SecretName:      "juicefs-secret",
					SecretNamespace: "kube-system",
				})
			})

			AfterEach(func() {
				SetCSIConfig(nil)
			})

			It("should create ReadWriteMany PV with Retain reclaim policy", func() {
				pv, err := buildSharedPV("shared-rw-pv", "", false)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv).NotTo(BeNil())
				Expect(pv.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadWriteMany}))
				Expect(pv.Spec.PersistentVolumeReclaimPolicy).To(Equal(corev1.PersistentVolumeReclaimRetain))
			})

			It("should create ReadOnlyMany PV when readOnly is true", func() {
				pv, err := buildSharedPV("shared-ro-pv", "", true)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadOnlyMany}))
			})

			It("should set subPath in VolumeAttributes when subPath is not empty", func() {
				pv, err := buildSharedPV("shared-rw-pv", "my/path", false)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv.Spec.CSI).NotTo(BeNil())
				Expect(pv.Spec.CSI.VolumeAttributes["subPath"]).To(Equal("my/path"))
			})

			It("should not set subPath in VolumeAttributes when subPath is empty", func() {
				pv, err := buildSharedPV("shared-rw-pv", "", false)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv.Spec.CSI).NotTo(BeNil())
				_, exists := pv.Spec.CSI.VolumeAttributes["subPath"]
				Expect(exists).To(BeFalse())
			})
		})
	})
})

