package devmachine

import (
	"context"
	"errors"
	"testing"

	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
	"go.uber.org/mock/gomock"
	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	networkingv1 "k8s.io/api/networking/v1"
	storagev1 "k8s.io/api/storage/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/config"
	devmachinemodel "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/devmachine"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/external/k8s"
	k8smock "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/external/k8s/mocks"
)

func TestDevMachine(t *testing.T) {
	RegisterFailHandler(Fail)
	RunSpecs(t, "DevMachine Service Suite")
}

var _ = Describe("DevMachine Service", func() {
	var (
		ctrl    *gomock.Controller
		k8sMock *k8smock.MockClient
		service Service
	)

	BeforeEach(func() {
		ctrl = gomock.NewController(GinkgoT())
		k8sMock = k8smock.NewMockClient(ctrl)

		// Mock GetStorageClass调用（NewService初始化时需要）
		reclaimPolicy := corev1.PersistentVolumeReclaimDelete
		bindingMode := storagev1.VolumeBindingImmediate
		k8sMock.EXPECT().GetStorageClass(gomock.Any(), "tdsc-sc").Return(&storagev1.StorageClass{
			ObjectMeta: metav1.ObjectMeta{
				Name: "tdsc-sc",
			},
			Provisioner:       "csi.juicefs.com",
			ReclaimPolicy:     &reclaimPolicy,
			VolumeBindingMode: &bindingMode,
			Parameters: map[string]string{
				"csi.storage.k8s.io/node-publish-secret-name":      "juicefs-secret",
				"csi.storage.k8s.io/node-publish-secret-namespace": "kube-system",
			},
		}, nil).AnyTimes()

		// Mock GetEndpoints调用（Ingress URL同步循环需要）
		k8sMock.EXPECT().GetEndpoints(gomock.Any(), "kube-system", "ingress-nginx-controller").
			Return(nil, errors.New("endpoint not found")).AnyTimes()

		cfg := &config.Config{
			InitContainer: config.InitContainerConfig{
				Image: "mock-image:latest",
			},
		}
		service = NewService(k8sMock, cfg)
	})

	AfterEach(func() {
		ctrl.Finish()
	})

	Describe("CreatePod", func() {
		Context("when create succeeds", func() {
			It("should create pod successfully", func() {
				pod := &k8s.PodSpec{
					Name:  "test-pod",
					Image: "nginx:latest",
				}
				k8sMock.EXPECT().CreatePod(gomock.Any(), gomock.Any()).Return(nil)

				err := service.CreatePod(context.Background(), pod)
				Expect(err).NotTo(HaveOccurred())
			})
		})

		Context("when pod name is empty", func() {
			It("should return error", func() {
				pod := &k8s.PodSpec{
					Name:  "",
					Image: "nginx:latest",
				}

				err := service.CreatePod(context.Background(), pod)
				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("pod name cannot be empty"))
			})
		})

		Context("when pod image is empty", func() {
			It("should return error", func() {
				pod := &k8s.PodSpec{
					Name:  "test-pod",
					Image: "",
				}

				err := service.CreatePod(context.Background(), pod)
				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("pod image cannot be empty"))
			})
		})

		Context("when k8s returns error", func() {
			It("should return error", func() {
				pod := &k8s.PodSpec{
					Name:  "test-pod",
					Image: "nginx:latest",
				}
				k8sMock.EXPECT().CreatePod(gomock.Any(), gomock.Any()).Return(errors.New("k8s error"))

				err := service.CreatePod(context.Background(), pod)
				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("k8s error"))
			})
		})
	})

	Describe("DeletePod", func() {
		It("should delete pod successfully", func() {
			k8sMock.EXPECT().DeletePod(gomock.Any(), "test-pod").Return(nil)

			err := service.DeletePod(context.Background(), "test-pod")
			Expect(err).NotTo(HaveOccurred())
		})
	})

	Describe("GetPod", func() {
		It("should get pod successfully", func() {
			k8sMock.EXPECT().GetPod(gomock.Any(), "test-pod").Return(&k8s.PodInfo{
				Name:   "test-pod",
				Status: "Running",
			}, nil)

			pod, err := service.GetPod(context.Background(), "test-pod")
			Expect(err).NotTo(HaveOccurred())
			Expect(pod.Name).To(Equal("test-pod"))
			Expect(pod.Status).To(Equal("Running"))
		})
	})

	Describe("ListPods", func() {
		It("should list pods successfully", func() {
			labels := map[string]string{"app": "test"}
			k8sMock.EXPECT().ListPods(gomock.Any(), labels).Return([]k8s.PodInfo{
				{Name: "test-pod", Status: "Running"},
			}, nil)

			pods, err := service.ListPods(context.Background(), labels)
			Expect(err).NotTo(HaveOccurred())
			Expect(pods).To(HaveLen(1))
			Expect(pods[0].Name).To(Equal("test-pod"))
		})
	})

	Describe("GetPodLogs", func() {
		It("should get pod logs successfully", func() {
			k8sMock.EXPECT().GetPodLogs(gomock.Any(), "test-pod", int64(100)).Return("test logs", nil)

			logs, err := service.GetPodLogs(context.Background(), "test-pod", int64(100))
			Expect(err).NotTo(HaveOccurred())
			Expect(logs).To(Equal("test logs"))
		})
	})

	Describe("CreateDevmachine", func() {
		var req *devmachinemodel.CreateDevmachineRequest

		BeforeEach(func() {
			req = &devmachinemodel.CreateDevmachineRequest{
				Namespace: "test-ns",
				Name:      "test-dm",
				ImageName: "registry/image:latest",
			}
		})

		Context("when request is invalid", func() {
			It("should return error without calling k8s", func() {
				req.Name = ""
				_, err := service.CreateDevmachine(context.Background(), req)
				Expect(err).To(HaveOccurred())
			})
		})

		Context("when storage list is empty", func() {
			It("should create Deployment, Service and Ingress without checking shared PVCs", func() {
				k8sMock.EXPECT().CreateDeployment(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateService(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateIngress(gomock.Any(), gomock.Any()).Return(nil)

				resp, err := service.CreateDevmachine(context.Background(), req)
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Name).To(Equal("test-dm"))
				Expect(resp.Status).To(Equal("pending"))
			})
		})

		Context("when storage has RW entry and shared PVC already exists", func() {
			It("should skip PVC creation and proceed to create devmachine resources", func() {
				req.Storage = []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
				}
				k8sMock.EXPECT().PVCExists(gomock.Any(), "test-ns", SharedRWPVCName).Return(true, nil)
				k8sMock.EXPECT().CreateDeployment(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateService(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateIngress(gomock.Any(), gomock.Any()).Return(nil)

				resp, err := service.CreateDevmachine(context.Background(), req)
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Name).To(Equal("test-dm"))
			})
		})

		Context("when storage has RW entry and shared PVC does not exist", func() {
			It("should create the shared RW PV+PVC before creating devmachine resources", func() {
				req.Storage = []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
				}
				k8sMock.EXPECT().PVCExists(gomock.Any(), "test-ns", SharedRWPVCName).Return(false, nil)
				k8sMock.EXPECT().PVExists(gomock.Any(), sharedRWPVName("test-ns")).Return(false, nil)
				k8sMock.EXPECT().CreatePV(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreatePVC(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateDeployment(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateService(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateIngress(gomock.Any(), gomock.Any()).Return(nil)

				resp, err := service.CreateDevmachine(context.Background(), req)
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Name).To(Equal("test-dm"))
			})
		})

		Context("when storage has both RW and RO entries and neither PVC exists", func() {
			It("should create both shared PVCs before creating devmachine resources", func() {
				req.Storage = []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
					{StoragePath: "shared/models", MountPath: "/models", ReadOnly: true},
				}
				k8sMock.EXPECT().PVCExists(gomock.Any(), "test-ns", SharedRWPVCName).Return(false, nil)
				k8sMock.EXPECT().PVCExists(gomock.Any(), "test-ns", SharedROPVCName).Return(false, nil)
				k8sMock.EXPECT().CreatePVC(gomock.Any(), gomock.Any()).Return(nil).Times(2)
				k8sMock.EXPECT().CreateDeployment(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateService(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateIngress(gomock.Any(), gomock.Any()).Return(nil)

				resp, err := service.CreateDevmachine(context.Background(), req)
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Name).To(Equal("test-dm"))
			})
		})

		Context("when storage has multiple RW entries", func() {
			It("should only check the RW PVC once regardless of how many RW storages exist", func() {
				req.Storage = []devmachinemodel.Storage{
					{StoragePath: "project/a", MountPath: "/a", ReadOnly: false},
					{StoragePath: "project/b", MountPath: "/b", ReadOnly: false},
				}
				// PVCExists should only be called once for RW despite two RW storages
				k8sMock.EXPECT().PVCExists(gomock.Any(), "test-ns", SharedRWPVCName).Return(true, nil).Times(1)
				k8sMock.EXPECT().CreateDeployment(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateService(gomock.Any(), gomock.Any()).Return(nil)
				k8sMock.EXPECT().CreateIngress(gomock.Any(), gomock.Any()).Return(nil)

				_, err := service.CreateDevmachine(context.Background(), req)
				Expect(err).NotTo(HaveOccurred())
			})
		})
	})

	Describe("DeleteDevmachine", func() {
		It("should delete Ingress, Service and Deployment without touching shared PVCs or PVs", func() {
			// gomock strict mode: any unexpected call to DeletePVC or DeletePV will fail the test
			k8sMock.EXPECT().DeleteIngress(gomock.Any(), "test-ns", "test-dm"+ingressSuffix).Return(nil)
			k8sMock.EXPECT().DeleteService(gomock.Any(), "test-ns", "test-dm"+serviceSuffix).Return(nil)
			k8sMock.EXPECT().DeleteDeployment(gomock.Any(), "test-ns", "test-dm").Return(nil)

			resp, err := service.DeleteDevmachine(context.Background(), "test-ns", "test-dm")
			Expect(err).NotTo(HaveOccurred())
			Expect(resp.DeleteAt).NotTo(BeEmpty())
		})
	})

	Describe("CreateNamespace", func() {
		Context("when namespace is empty", func() {
			It("should return a validation error", func() {
				_, err := service.CreateNamespace(context.Background(), &devmachinemodel.CreateNamespaceRequest{
					Namespace: "",
				})
				Expect(err).To(HaveOccurred())
			})
		})

		Context("when k8s namespace creation fails", func() {
			It("should return error without creating PVCs", func() {
				k8sMock.EXPECT().CreateNamespace(gomock.Any(), "new-ns").Return(errors.New("k8s error"))

				_, err := service.CreateNamespace(context.Background(), &devmachinemodel.CreateNamespaceRequest{
					Namespace: "new-ns",
				})
				Expect(err).To(HaveOccurred())
			})
		})

		Context("when namespace creation succeeds", func() {
			It("should create shared RW and RO PVCs in the new namespace", func() {
				k8sMock.EXPECT().CreateNamespace(gomock.Any(), "new-ns").Return(nil)
				k8sMock.EXPECT().CreatePVC(gomock.Any(), gomock.Any()).Return(nil).Times(2)

				resp, err := service.CreateNamespace(context.Background(), &devmachinemodel.CreateNamespaceRequest{
					Namespace: "new-ns",
				})
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Message).To(ContainSubstring("new-ns"))
			})
		})

		Context("when shared PVC creation fails after namespace creation", func() {
			It("should still succeed because PVC failure is non-fatal", func() {
				k8sMock.EXPECT().CreateNamespace(gomock.Any(), "new-ns").Return(nil)
				// RW PVC creation fails, which stops createSharedPVCs early (RO PVC won't be attempted)
				k8sMock.EXPECT().CreatePVC(gomock.Any(), gomock.Any()).Return(errors.New("pvc error"))

				resp, err := service.CreateNamespace(context.Background(), &devmachinemodel.CreateNamespaceRequest{
					Namespace: "new-ns",
				})
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Message).To(ContainSubstring("new-ns"))
			})
		})
	})

	Describe("GetDevmachine", func() {
		buildTestDeployment := func(vmounts []corev1.VolumeMount) *appsv1.Deployment {
			return &appsv1.Deployment{
				ObjectMeta: metav1.ObjectMeta{
					Name:        "test-dm",
					Namespace:   "test-ns",
					Labels:      map[string]string{},
					Annotations: map[string]string{},
				},
				Spec: appsv1.DeploymentSpec{
					Template: corev1.PodTemplateSpec{
						ObjectMeta: metav1.ObjectMeta{
							Annotations: map[string]string{volcanoQueueName: ""},
						},
						Spec: corev1.PodSpec{
							Containers: []corev1.Container{
								{
									Image:        "registry/image:latest",
									VolumeMounts: vmounts,
									Resources:    corev1.ResourceRequirements{},
								},
							},
						},
					},
				},
			}
		}

		Context("when devmachine has both RW and RO shared storage mounts", func() {
			It("should read storage list from volumeMounts using volume name and subPath", func() {
				vmounts := []corev1.VolumeMount{
					{Name: devVolumeName, MountPath: "/opt/dev"},
					{Name: SharedRWVolumeName, MountPath: "/workspace/data", SubPath: "user/data", ReadOnly: false},
					{Name: SharedROVolumeName, MountPath: "/models", SubPath: "shared/models", ReadOnly: true},
				}
				k8sMock.EXPECT().GetDeployment(gomock.Any(), "test-ns", "test-dm").Return(buildTestDeployment(vmounts), nil)
				k8sMock.EXPECT().GetService(gomock.Any(), "test-ns", "test-dm"+serviceSuffix).Return(&corev1.Service{}, nil)
				k8sMock.EXPECT().GetIngress(gomock.Any(), "test-ns", "test-dm"+ingressSuffix).Return(&networkingv1.Ingress{}, nil)

				resp, err := service.GetDevmachine(context.Background(), "test-ns", "test-dm")
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Devmachine.Storage).To(HaveLen(2))

				Expect(resp.Devmachine.Storage[0].MountPath).To(Equal("/workspace/data"))
				Expect(resp.Devmachine.Storage[0].StoragePath).To(Equal("user/data"))
				Expect(resp.Devmachine.Storage[0].ReadOnly).To(BeFalse())

				Expect(resp.Devmachine.Storage[1].MountPath).To(Equal("/models"))
				Expect(resp.Devmachine.Storage[1].StoragePath).To(Equal("shared/models"))
				Expect(resp.Devmachine.Storage[1].ReadOnly).To(BeTrue())
			})
		})

		Context("when devmachine has no shared storage volume mounts", func() {
			It("should return an empty storage list", func() {
				vmounts := []corev1.VolumeMount{
					{Name: devVolumeName, MountPath: "/opt/dev"},
				}
				k8sMock.EXPECT().GetDeployment(gomock.Any(), "test-ns", "test-dm").Return(buildTestDeployment(vmounts), nil)
				k8sMock.EXPECT().GetService(gomock.Any(), "test-ns", "test-dm"+serviceSuffix).Return(&corev1.Service{}, nil)
				k8sMock.EXPECT().GetIngress(gomock.Any(), "test-ns", "test-dm"+ingressSuffix).Return(&networkingv1.Ingress{}, nil)

				resp, err := service.GetDevmachine(context.Background(), "test-ns", "test-dm")
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Devmachine.Storage).To(BeEmpty())
			})
		})

		Context("when devmachine has multiple mounts sharing the same RW volume", func() {
			It("should return one storage entry per volumeMount with correct subPaths", func() {
				vmounts := []corev1.VolumeMount{
					{Name: SharedRWVolumeName, MountPath: "/data/a", SubPath: "project/a", ReadOnly: false},
					{Name: SharedRWVolumeName, MountPath: "/data/b", SubPath: "project/b", ReadOnly: false},
				}
				k8sMock.EXPECT().GetDeployment(gomock.Any(), "test-ns", "test-dm").Return(buildTestDeployment(vmounts), nil)
				k8sMock.EXPECT().GetService(gomock.Any(), "test-ns", "test-dm"+serviceSuffix).Return(&corev1.Service{}, nil)
				k8sMock.EXPECT().GetIngress(gomock.Any(), "test-ns", "test-dm"+ingressSuffix).Return(&networkingv1.Ingress{}, nil)

				resp, err := service.GetDevmachine(context.Background(), "test-ns", "test-dm")
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Devmachine.Storage).To(HaveLen(2))
				Expect(resp.Devmachine.Storage[0].StoragePath).To(Equal("project/a"))
				Expect(resp.Devmachine.Storage[1].StoragePath).To(Equal("project/b"))
			})
		})
	})
})

