package devmachine

import (
	"context"
	"fmt"
	"log"
	"time"

	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/client-go/util/workqueue"
	"k8s.io/utils/ptr"

	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/config"
	devmachinemodel "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/devmachine"
	k8s "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/external/k8s"
)

// Service 开发机服务接口
type Service interface {
	CreatePod(ctx context.Context, pod *k8s.PodSpec) error
	DeletePod(ctx context.Context, name string) error
	GetPod(ctx context.Context, name string) (*k8s.PodInfo, error)
	ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error)
	GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error)

	CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error)
	UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error)
	DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error)
	GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error)
	ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error)
	StartDevmachine(ctx context.Context, namespace, name string) error
	StopDevmachine(ctx context.Context, namespace, name string) error
	GetDevmachineStatus(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineStatusResponse, error)
	CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error)
}

type service struct {
	k8sClient k8s.Client
	config    *config.Config
}

// NewService 创建开发机服务
func NewService(k8sClient k8s.Client, cfg *config.Config) Service {
	// 初始化CSI配置
	if err := SyncCSIConfigFromStorageClass(k8sClient); err != nil {
		log.Printf("warning: failed to sync CSI config from storage class: %v", err)
	}

	// 启动CSI配置同步循环
	StartCSISyncLoop(k8sClient)

	// 启动Ingress URL同步循环
	StartIngressURLSyncLoop(k8sClient)

	return &service{k8sClient: k8sClient, config: cfg}
}

func (s *service) CreatePod(ctx context.Context, pod *k8s.PodSpec) error {
	if err := ValidatePodRequest(pod.Name, pod.Image); err != nil {
		return NewValidationError("pod.Name", pod.Name, err)
	}
	return s.k8sClient.CreatePod(ctx, pod)
}

func (s *service) DeletePod(ctx context.Context, name string) error {
	if err := ValidatePodName(name); err != nil {
		return NewValidationError("pod.Name", name, err)
	}
	return s.k8sClient.DeletePod(ctx, name)
}

func (s *service) GetPod(ctx context.Context, name string) (*k8s.PodInfo, error) {
	if err := ValidatePodName(name); err != nil {
		return nil, NewValidationError("pod.Name", name, err)
	}
	return s.k8sClient.GetPod(ctx, name)
}

func (s *service) ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error) {
	return s.k8sClient.ListPods(ctx, labels)
}

func (s *service) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
	if err := ValidatePodName(name); err != nil {
		return "", NewValidationError("pod.Name", name, err)
	}
	if tailLines <= 0 {
		tailLines = 100
	}
	return s.k8sClient.GetPodLogs(ctx, name, tailLines)
}

func (s *service) CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error) {
	// 验证请求参数
	if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
		return nil, NewValidationError("devmachine", request.Name, err)
	}

	var err error

	defer func() {
		if err != nil {
			log.Printf("error: failed to create devmachine, try to cleanup: %v", err)
			_, _ = s.DeleteDevmachine(ctx, request.Namespace, request.Name)
		}
	}()

	// 1. 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 补建）
	// TODO: 新环境稳定后可移除此兼容逻辑
	if len(request.Storage) > 0 {
		if err = s.ensureSharedPVCs(ctx, request.Namespace, request.Storage); err != nil {
			return nil, err
		}
	}

	// 3. 创建 Deployment
	deployment := generateDevMachineDeployment(request, s.config.InitContainer.Image)
	if err := s.k8sClient.CreateDeployment(ctx, deployment); err != nil {
		return nil, NewResourceError("Deployment", request.Name, "create", err)
	}

	// 3. 创建 Service
	service := generateDevMachineService(request)
	if err := s.k8sClient.CreateService(ctx, service); err != nil {
		return nil, NewResourceError("Service", request.Name+serviceSuffix, "create", err)
	}

	// 4. 创建 Ingress
	ingress := generateDevMachineIngress(request)
	if err := s.k8sClient.CreateIngress(ctx, ingress); err != nil {
		return nil, NewResourceError("Ingress", request.Name+ingressSuffix, "create", err)
	}

	return &devmachinemodel.CreateDevmachineResponse{
		Name:   request.Name,
		Status: "pending",
		WebUrl: fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(request.Namespace, request.Name)),
	}, nil
}

func (s *service) UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error) {
	// 验证请求参数
	if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
		return nil, NewValidationError("devmachine", request.Name, err)
	}

	// 1. 获取现有 Deployment
	deployment, err := s.k8sClient.GetDeployment(ctx, request.Namespace, request.Name)
	if err != nil {
		return nil, NewResourceError("Deployment", request.Name, "get", err)
	}

	// 2. 更新 Deployment 配置
	deployment.Spec.Template.Spec.Containers[0].Image = request.ImageName

	// 更新资源请求
	if request.CPU != "" || request.Memory != "" || request.GPU != "" {
		// 构建新的资源请求
		resources := BuildResourceRequirements(request.CPU, request.Memory, request.GPU, request.GPUName)
		deployment.Spec.Template.Spec.Containers[0].Resources = resources
	}

	// 更新节点选择器
	if len(request.NodeSelector) > 0 {
		deployment.Spec.Template.Spec.NodeSelector = request.NodeSelector
	}

	// 更新标签
	if len(request.Labels) > 0 {
		for k, v := range request.Labels {
			deployment.Labels[k] = v
			deployment.Spec.Template.Labels[k] = v
		}
	}

	// 更新注解
	if len(request.Annotations) > 0 {
		for k, v := range request.Annotations {
			deployment.Annotations[k] = v
			deployment.Spec.Template.Annotations[k] = v
		}
	}

	// 更新队列名称
	if request.QueueName != "" {
		deployment.Spec.Template.Annotations[volcanoQueueName] = request.QueueName
	}

	// 3. 更新 Deployment
	if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
		return nil, NewResourceError("Deployment", request.Name, "update", err)
	}

	// 返回更新时间
	return &devmachinemodel.UpdateDevmachineResponse{
		UpdateAt: time.Now().Format(time.RFC3339),
	}, nil
}

func (s *service) DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error) {
	// 1. 删除 Ingress
	if err := s.k8sClient.DeleteIngress(ctx, namespace, name+ingressSuffix); err != nil {
		// 记录错误但继续删除其他资源
		log.Printf("warning: failed to delete ingress: %v\n", err)
	}

	// 2. 删除 Service
	if err := s.k8sClient.DeleteService(ctx, namespace, name+serviceSuffix); err != nil {
		log.Printf("warning: failed to delete service: %v\n", err)
	}

	// 3. 删除 Deployment
	if err := s.k8sClient.DeleteDeployment(ctx, namespace, name); err != nil {
		log.Printf("warning: failed to delete deployment: %v\n", err)
	}

	// PVC 和 PV 为共享资源，随 namespace 生命周期管理，不随开发机删除

	// 返回删除时间
	return &devmachinemodel.DeleteDevmachineResponse{
		DeleteAt: time.Now().Format(time.RFC3339),
	}, nil
}

func (s *service) GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error) {
	// 验证请求参数
	if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
		return nil, NewValidationError("devmachine", name, err)
	}

	// 获取 Deployment 信息
	deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
	if err != nil {
		return nil, NewResourceError("Deployment", name, "get", err)
	}

	// 获取 Service 信息
	service, err := s.k8sClient.GetService(ctx, namespace, name+serviceSuffix)
	if err != nil {
		return nil, NewResourceError("Service", name+serviceSuffix, "get", err)
	}

	// 获取 Ingress 信息
	ingress, err := s.k8sClient.GetIngress(ctx, namespace, name+ingressSuffix)
	if err != nil {
		return nil, NewResourceError("Ingress", name+ingressSuffix, "get", err)
	}

	if deployment == nil || service == nil || ingress == nil {
		return nil, fmt.Errorf("deployment or service or ingress not found")
	}

	// 获取与Deployment关联的存储信息（从 volumeMounts 的 subPath 读取，共享PVC模式）
	var storage []devmachinemodel.Storage
	if len(deployment.Spec.Template.Spec.Containers) > 0 {
		container := deployment.Spec.Template.Spec.Containers[0]
		for _, vm := range container.VolumeMounts {
			if vm.Name == SharedRWVolumeName || vm.Name == SharedROVolumeName {
				storage = append(storage, devmachinemodel.Storage{
					MountPath:   vm.MountPath,
					StoragePath: vm.SubPath,
					ReadOnly:    vm.ReadOnly,
				})
			}
		}
	}

	// 提取 GPU 信息
	gpu := "0"
	gpuName := ""
	if len(deployment.Spec.Template.Spec.Containers) > 0 {
		container := deployment.Spec.Template.Spec.Containers[0]
		if gpuResource, exists := container.Resources.Requests["hygon.com/dcu"]; exists {
			gpu = gpuResource.String()
			gpuName = "hygon.com/dcu"
		} else if gpuResource, exists := container.Resources.Requests["nvidia.com/gpu"]; exists {
			gpu = gpuResource.String()
			gpuName = "nvidia.com/gpu"
		}
	}

	// 获取 WebIDE 类型
	webIDE := GetWebIDEType(deployment)

	// 构建响应
	response := &devmachinemodel.GetDevmachineResponse{
		Devmachine: devmachinemodel.Devmachine{
			Namespace:   deployment.Namespace,
			Name:        deployment.Name,
			QueueName:   deployment.Spec.Template.Annotations[volcanoQueueName],
			ImageName:   deployment.Spec.Template.Spec.Containers[0].Image,
			CPU:         deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Cpu().String(),
			Memory:      deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Memory().String(),
			GPU:         gpu,
			GPUName:     gpuName,
			WebIDE:      webIDE,
			WebUrl:      fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(namespace, name)),
			Storage:     storage,
			Annotations: deployment.Annotations,
			Labels:      deployment.Labels,
		},
	}

	// 填充 Pod 级别的细粒度状态
	status, reason, message, ready, podName := s.resolveStatus(ctx, namespace, deployment)
	response.Devmachine.Status = status
	response.Devmachine.Reason = reason
	response.Devmachine.Message = message
	response.Devmachine.Ready = ready
	response.Devmachine.PodName = podName

	return response, nil
}

// resolveStatus 查询 Pod 并推导开发机当前所处的生命周期状态，供 GetDevmachine 和 GetDevmachineStatus 共用
func (s *service) resolveStatus(ctx context.Context, namespace string, deployment *appsv1.Deployment) (status, reason, message string, ready bool, podName string) {
	// 副本数为 0，开发机已停止
	if deployment.Spec.Replicas != nil && *deployment.Spec.Replicas == 0 {
		return devmachinemodel.StatusStopped, "", "开发机已停止", false, ""
	}

	// 通过 Deployment 的标签选择器查询对应的 Pod
	pods, err := s.k8sClient.GetPodsByLabelSelector(ctx, namespace, deployment.Spec.Selector.MatchLabels)
	if err != nil || len(pods) == 0 {
		// Pod 尚未创建（Deployment 刚下发，controller 还未生成 Pod）
		return devmachinemodel.StatusScheduling, "", "等待 Pod 创建", false, ""
	}

	// 取最新创建的 Pod 作为当前状态来源
	pod := getLatestPod(pods)
	status, reason, message, ready = getStatusFromPod(pod)
	return status, reason, message, ready, pod.Name
}

func (s *service) ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error) {
	// 如果没有指定任何devmachine，则返回空列表
	if len(devmachines) == 0 {
		return []devmachinemodel.Devmachine{}, nil
	}

	// 初始化结果切片
	results := make([]devmachinemodel.Devmachine, len(devmachines))
	errors := make([]error, len(devmachines))

	// 定义工作函数
	workerFunc := func(piece int) {
		// 获取指定的devmachine
		devmachine := devmachines[piece]
		// 调用GetDevmachine获取详细信息
		result, err := s.GetDevmachine(ctx, devmachine.Namespace, devmachine.Name)
		if err != nil {
			errors[piece] = err
		} else {
			results[piece] = result.Devmachine
		}
	}

	// 使用workqueue.ParallelizeUntil进行并行处理
	// 限制最大并发数以避免对k8s API服务器造成过大压力
	maxWorkers := 10
	workqueue.ParallelizeUntil(ctx, maxWorkers, len(devmachines), workerFunc)

	// 收集成功的结果
	var successfulResults []devmachinemodel.Devmachine
	for i, err := range errors {
		if err == nil {
			successfulResults = append(successfulResults, results[i])
		} else {
			log.Printf("warning: failed to get devmachine %s/%s: %v", devmachines[i].Namespace, devmachines[i].Name, err)
		}
	}

	return successfulResults, nil
}

func (s *service) StartDevmachine(ctx context.Context, namespace, name string) error {
	// 验证请求参数
	if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
		return NewValidationError("devmachine", name, err)
	}

	// 获取 Deployment
	deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
	if err != nil {
		return NewResourceError("Deployment", name, "get", err)
	}

	// 设置 replicas 为 1
	deployment.Spec.Replicas = ptr.To[int32](1)

	// 更新 Deployment
	if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
		return NewResourceError("Deployment", name, "update", err)
	}

	return nil
}

